previewCss:
.darma-loader-sliding-bars {
  position: relative;
  display: inline-block;
  width: 88px;
  height: 12px;
  overflow: hidden;
  border-radius: 999px;
  background: color-mix(in srgb, var(--loader-color, #6366f1) 16%, transparent);
}
.darma-loader-sliding-bars::before {
  content: "";
  position: absolute;
  inset: 0 auto 0 0;
  width: 38%;
  border-radius: inherit;
  background: var(--loader-color, #6366f1);
  animation: darma-loader-sliding-bars-slide 1s ease-in-out infinite;
}
@keyframes darma-loader-sliding-bars-slide {
  0% { transform: translateX(-100%); }
  100% { transform: translateX(270%); }
}

